mapper.select:
SELECT o.*, m.shop_name as merchantShopName FROM orders o
LEFT JOIN merchants m ON o.merchant_id = m.id
WHERE o.order_no = #{orderNo}

mapper.update:
UPDATE orders SET
    status = #{status},
    accepted_at = #{acceptedAt},
    delivered_at = #{deliveredAt},
    completed_at = #{completedAt}
WHERE id = #{id}
